/** Exhaustive pair comparison over the documented small RDF4J-runtime universe. */
@Tag("slow")
class RuntimeBoundedUniverseTest {
	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI S0 = VF.createIRI("urn:bounded:s0");
	private static final IRI S1 = VF.createIRI("urn:bounded:s1");
	private static final IRI P = VF.createIRI("urn:bounded:p");
	private static final IRI O = VF.createIRI("urn:bounded:o");
	private static final IRI G = VF.createIRI("urn:bounded:g");

	@Test
	void everyRuntimeVerdictAgreesWithTheFiniteReferenceUniverse() {
		List<TupleExpr> expressions = expressions();
		assertPairwiseStructurallyDistinct(expressions);

		int comparedPairs = 0;
		int equivalentVerdicts = 0;
		int witnessVerdicts = 0;
		for (ContextMode context : ContextMode.values()) {
			List<EvaluationCase> cases = evaluationCases(context);
			Map<Integer, List<EvaluationOutcome>> outcomes = evaluateAll(expressions, cases);
			for (ObservationMode observation : ObservationMode.values()) {
				CheckOptions options = CheckOptions.builder()
						.semanticsTarget(SemanticsTarget.RDF4J_RUNTIME)
						.observationMode(observation)
						.contextMode(context)
						.evaluationCases(cases)
						.maxResultRows(128)
						.build();
				AlgebraEquivalenceChecker checker = new AlgebraEquivalenceChecker(options);
				ProofKernel kernel = new ProofKernel(options);
				for (int leftIndex = 0; leftIndex < expressions.size(); leftIndex++) {
					for (int rightIndex = leftIndex; rightIndex < expressions.size(); rightIndex++) {
						int leftPosition = leftIndex;
						int rightPosition = rightIndex;
						TupleExpr left = expressions.get(leftIndex);
						TupleExpr right = expressions.get(rightIndex);
						EquivalenceResult result = checker.check(left, right);
						comparedPairs++;
						if (result.getStatus() == EquivalenceStatus.EQUIVALENT) {
							equivalentVerdicts++;
							EquivalenceEvidence evidence = result.getEvidence().orElseThrow();
							assertTrue(kernel.verify(left, right, evidence), () -> profile(context, observation)
									+ " kernel rejected " + leftPosition + " ~ " + rightPosition);
							assertObservedEqual(
									outcomes.get(leftIndex),
									outcomes.get(rightIndex),
									observation,
									profile(context, observation) + " false EQUIVALENT " + leftPosition + " ~ "
											+ rightPosition);
						} else if (result.getStatus() == EquivalenceStatus.NOT_EQUIVALENT) {
							witnessVerdicts++;
							Counterexample witness = result.getEvidence()
									.filter(Counterexample.class::isInstance)
									.map(Counterexample.class::cast)
									.orElseThrow();
							assertEquals(SemanticsTarget.RDF4J_RUNTIME, witness.getSemanticsTarget());
							assertFalse(witness.getOracleVersion().isBlank());
							assertWitness(left, right, witness, observation);
						}

						EquivalenceResult swapped = checker.check(right, left);
						assertFalse(
								conflicts(result.getStatus(), swapped.getStatus()),
								() -> profile(context, observation) + " asymmetric conflict " + leftPosition + " ~ "
										+ rightPosition);
					}
				}
			}
		}

		System.out.println("[runtime-bounded] expressions=" + expressions.size()
				+ " comparedProfilesAndPairs=" + comparedPairs
				+ " equivalent=" + equivalentVerdicts
				+ " notEquivalent=" + witnessVerdicts);
	}

	private static List<TupleExpr> expressions() {
		StatementPattern x = pattern("x");
		StatementPattern y = pattern("y");
		StatementPattern named = new StatementPattern(
				StatementPattern.Scope.NAMED_CONTEXTS,
				Var.of("s"),
				Var.of("p", P),
				Var.of("o"),
				Var.of("g"));
		List<TupleExpr> result = new ArrayList<>();
		result.add(new EmptySet());
		result.add(new SingletonSet());
		result.add(values(List.of()));
		result.add(values(List.of(EmptyBindingSet.getInstance())));
		result.add(values(List.of(row("x", S0))));
		result.add(values(List.of(row("x", S0), row("x", S0))));
		result.add(x);
		result.add(y);
		result.add(new StatementPattern(Var.of("same"), Var.of("p", P), Var.of("same")));
		result.add(named);
		result.add(new Join(pattern("x"), new SingletonSet()));
		result.add(new Join(new SingletonSet(), pattern("x")));
		result.add(new Join(pattern("x"), pattern("y")));
		result.add(new Join(pattern("x"), new EmptySet()));
		result.add(new Union(pattern("x"), new EmptySet()));
		result.add(new Union(new EmptySet(), pattern("x")));
		result.add(new Union(pattern("x"), pattern("x")));
		result.add(new Filter(pattern("x"), new ValueConstant(VF.createLiteral(true))));
		result.add(new Filter(pattern("x"), new ValueConstant(VF.createLiteral(false))));
		result.add(new Filter(pattern("x"), new Bound(Var.of("x"))));
		result.add(new Filter(pattern("x"), new ValueConstant(O)));
		result.add(new Filter(pattern("x"), new FunctionCall("urn:bounded:missing-function")));
		result.add(new LeftJoin(pattern("x"), new EmptySet()));
		result.add(new LeftJoin(pattern("x"), new SingletonSet()));
		result.add(new LeftJoin(pattern("x"), pattern("y")));
		result.add(new Difference(pattern("x"), new EmptySet()));
		result.add(new Difference(pattern("x"), new SingletonSet()));
		result.add(new Difference(pattern("x"), pattern("y")));
		result.add(new Distinct(pattern("x")));
		result.add(new Distinct(new Distinct(pattern("x"))));
		result.add(new Reduced(pattern("x")));
		result.add(new Projection(pattern("x"), new ProjectionElemList(new ProjectionElem("x"))));
		return List.copyOf(result);
	}

	private static List<EvaluationCase> evaluationCases(ContextMode context) {
		List<List<org.eclipse.rdf4j.model.Statement>> datasets = List.of(
				List.of(),
				List.of(VF.createStatement(S0, P, O)),
				List.of(VF.createStatement(S0, P, O), VF.createStatement(S1, P, VF.createLiteral("literal"))),
				List.of(VF.createStatement(S0, P, O, G)),
				List.of(VF.createStatement(S0, P, VF.createTripleTerm(S0, P, O))));
		List<BindingSet> incoming = new ArrayList<>();
		incoming.add(EmptyBindingSet.getInstance());
		if (context == ContextMode.ALL_BINDINGS) {
			incoming.add(row("x", S0));
			incoming.add(row("y", S1));
			incoming.add(row("x", O));
		}

		List<EvaluationCase> result = new ArrayList<>();
		for (int datasetIndex = 0; datasetIndex < datasets.size(); datasetIndex++) {
			for (int incomingIndex = 0; incomingIndex < incoming.size(); incomingIndex++) {
				result.add(EvaluationCase.builder("bounded-d" + datasetIndex + "-b" + incomingIndex)
						.statements(datasets.get(datasetIndex))
						.initialBindings(incoming.get(incomingIndex))
						.build());
			}
		}
		return List.copyOf(result);
	}

	private static Map<Integer, List<EvaluationOutcome>> evaluateAll(
			List<TupleExpr> expressions,
			List<EvaluationCase> cases) {
		Map<Integer, List<EvaluationOutcome>> outcomes = new HashMap<>();
		Rdf4jEvaluator evaluator = new Rdf4jEvaluator();
		for (int expressionIndex = 0; expressionIndex < expressions.size(); expressionIndex++) {
			int currentExpression = expressionIndex;
			List<EvaluationOutcome> perCase = new ArrayList<>();
			for (EvaluationCase evaluationCase : cases) {
				EvaluationAttempt attempt = evaluator.evaluate(expressions.get(expressionIndex), evaluationCase, 128);
				assertTrue(attempt.isComplete(),
						() -> "bounded evaluation truncated for expression " + currentExpression
								+ " case " + evaluationCase.getLabel());
				perCase.add(attempt.getOutcome().orElseThrow());
			}
			outcomes.put(expressionIndex, List.copyOf(perCase));
		}
		return outcomes;
	}

	private static void assertObservedEqual(
			List<EvaluationOutcome> left,
			List<EvaluationOutcome> right,
			ObservationMode observation,
			String message) {
		assertEquals(left.size(), right.size());
		for (int caseIndex = 0; caseIndex < left.size(); caseIndex++) {
			int current = caseIndex;
			assertTrue(
					left.get(caseIndex).sameAs(right.get(caseIndex), observation),
					() -> message + " on case " + current + ": " + left.get(current) + " != " + right.get(current));
		}
	}

	private static void assertWitness(
			TupleExpr left,
			TupleExpr right,
			Counterexample witness,
			ObservationMode observation) {
		for (int replay = 0; replay < 2; replay++) {
			EvaluationOutcome leftOutcome = new Rdf4jEvaluator()
					.evaluate(left, witness.getEvaluationCase(), 128)
					.getOutcome()
					.orElseThrow();
			EvaluationOutcome rightOutcome = new Rdf4jEvaluator()
					.evaluate(right, witness.getEvaluationCase(), 128)
					.getOutcome()
					.orElseThrow();
			assertFalse(leftOutcome.sameAs(rightOutcome, observation));
		}
	}

	private static void assertPairwiseStructurallyDistinct(List<TupleExpr> expressions) {
		for (int left = 0; left < expressions.size(); left++) {
			for (int right = left + 1; right < expressions.size(); right++) {
				int leftIndex = left;
				int rightIndex = right;
				assertFalse(
						ExactTreeEquality.equal(expressions.get(left), expressions.get(right)),
						() -> "duplicate expressions " + leftIndex + " and " + rightIndex);
			}
		}
	}

	private static boolean conflicts(EquivalenceStatus first, EquivalenceStatus second) {
		return first == EquivalenceStatus.EQUIVALENT && second == EquivalenceStatus.NOT_EQUIVALENT
				|| first == EquivalenceStatus.NOT_EQUIVALENT && second == EquivalenceStatus.EQUIVALENT;
	}

	private static String profile(ContextMode context, ObservationMode observation) {
		return "runtime/" + observation + "/" + context;
	}

	private static StatementPattern pattern(String objectName) {
		return new StatementPattern(Var.of("s"), Var.of("p", P), Var.of(objectName));
	}

	private static BindingSetAssignment values(List<BindingSet> rows) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setDeclaredBindingNames(Set.of("x"));
		assignment.setBindingSets(rows);
		return assignment;
	}

	private static MapBindingSet row(String name, Value value) {
		MapBindingSet row = new MapBindingSet();
		row.setBinding(name, value);
		return row;
	}
}
